solution_code:
import numpy as np

class NumpyDataset:
    def __init__(self, X: np.ndarray, y: np.ndarray):
        assert len(X) == len(y)
        self.X = X
        self.y = y

    def __len__(self) -> int:
        return len(self.X)

    def __getitem__(self, idx: int) -> tuple:
        return self.X[idx], self.y[idx]


# Alias for PyTorch naming convention
TensorDataset = NumpyDataset


class DataLoader:
    def __init__(self, dataset: NumpyDataset, batch_size: int = 32, shuffle: bool = False):
        self.dataset = dataset
        self.batch_size = batch_size
        self.shuffle = shuffle

    def __iter__(self):
        N = len(self.dataset)
        indices = np.random.permutation(N) if self.shuffle else np.arange(N)
        for start in range(0, N, self.batch_size):
            batch_idx = indices[start:start + self.batch_size]
            X_batch = np.stack([self.dataset[i][0] for i in batch_idx])
            y_batch = np.stack([self.dataset[i][1] for i in batch_idx])
            yield X_batch, y_batch

    def __len__(self) -> int:
        import math
        return math.ceil(len(self.dataset) / self.batch_size)


def train_test_split(
    X: np.ndarray,
    y: np.ndarray,
    test_size: float = 0.2,
    random_state: int = None
) -> tuple:
    if random_state is not None:
        np.random.seed(random_state)
    N = len(X)
    n_test = max(1, int(N * test_size))
    indices = np.random.permutation(N)
    test_idx = indices[:n_test]
    train_idx = indices[n_test:]
    return X[train_idx], X[test_idx], y[train_idx], y[test_idx]
